import { Navbar, Nav, Container } from 'react-bootstrap';
import React, { useEffect, useState, useContext } from 'react';
import { withRouter } from 'react-router';
import { NavLink } from 'react-router-dom';
import styled, { ThemeContext } from 'styled-components';
import endpoints from '../constants/endpoints';
import ThemeToggler from './ThemeToggler';

const styles = {
  logoStyle: {
    width: 50,
    height: 40,
  },
};

const ExternalNavLink = styled.a`
  color: ${(props) => props.theme.navbarTheme.linkColor};
  &:hover {
    color: ${(props) => props.theme.navbarTheme.linkHoverColor};
  }
  &::after {
    background-color: ${(props) => props.theme.accentColor};
  }
`;

const InternalNavLink = styled(NavLink)`
  color: ${(props) => props.theme.navbarTheme.linkColor};
  &:hover {
    color: ${(props) => props.theme.navbarTheme.linkHoverColor};
  }
  &::after {
    background-color: ${(props) => props.theme.accentColor};
  }
  &.navbar__link--active {
    color: ${(props) => props.theme.navbarTheme.linkActiveColor};
  }
`;

const NavBar = () => {
  const theme = useContext(ThemeContext);
  const [data, setData] = useState(null);
  const [expanded, setExpanded] = useState(false);
  const [isListening, setIsListening] = useState(false);

  useEffect(() => {
    fetch(endpoints.navbar, {
      method: 'GET',
    })
      .then((res) => res.json())
      .then((res) => setData(res))
      .catch((err) => err);
  }, []);

  const speakMessage = (message) => {
    const synth = window.speechSynthesis;
    const utterance = new SpeechSynthesisUtterance(message);
    synth.speak(utterance);
  };

  const processCommand = (command) => {
    if (command.includes('home page') || command.includes('home section')) {
      window.location.href = '/';
      speakMessage('Going to home page');
    } else if (command.includes('about page') || command.includes('about section')) {
      window.location.href = '/about';
      speakMessage('Going to about page');
    } else if (command.includes('skills page') || command.includes('skills section')) {
      window.location.href = '/skills';
      speakMessage('Going to skills page');
    } else if (command.includes('experience page') || command.includes('experience section')) {
      window.location.href = '/experience';
      speakMessage('Going to experience page');
    } else if (command.includes('projects page') || command.includes('projects section')) {
      window.location.href = '/projects';
      speakMessage('Going to projects page');
    } else {
      speakMessage('Sorry, this page does not exist.');
    }
  };


  const handleMicClick = () => {
    const recognition = new (window.SpeechRecognition || window.webkitSpeechRecognition)();
    recognition.lang = 'en-US';
    recognition.interimResults = false;

    recognition.onstart = () => {
      setIsListening(true);
    };

    recognition.onend = () => {
      setIsListening(false);
    };

    recognition.onresult = (event) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      console.log("transcript", transcript);
      processCommand(transcript);
    };

    recognition.start();
  };

  return (
    <Navbar
      fixed="top"
      expand="md"
      bg="dark"
      variant="dark"
      className="navbar-custom"
      expanded={expanded}
    >
      <Container>
        {data?.logo && (
          <Navbar.Brand href="/">
            <img
              src={`${process.env.PUBLIC_URL}/${data?.logo?.source}`}
              className="d-inline-block align-top"
              alt="main logo"
              style={
                data?.logo?.height && data?.logo?.width
                  ? { height: data?.logo?.height, width: data?.logo?.width }
                  : styles.logoStyle
              }
            />
            {/* <div
              style={{
                fontFamily: '"Cedarville Cursive", serif',
                fontWeight: 400,
                fontStyle: "normal",
              }}
            >
              Aowwwww
            </div> */}
          </Navbar.Brand>
        )}
        <Navbar.Toggle
          aria-controls="responsive-navbar-nav"
          onClick={() => setExpanded(!expanded)}
        />
        <Navbar.Collapse id="responsive-navbar-nav">
          <Nav className="me-auto" />
          <Nav>
            {data
              && data.sections?.map((section, index) => (section?.type === 'link' ? (
                <ExternalNavLink
                  key={section.title}
                  href={section.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  onClick={() => setExpanded(false)}
                  className="navbar__link"
                  theme={theme}
                >
                  {section.title}
                </ExternalNavLink>
              ) : (
                <InternalNavLink
                  key={section.title}
                  onClick={() => setExpanded(false)}
                  exact={index === 0}
                  activeClassName="navbar__link--active"
                  className="navbar__link"
                  to={section.href}
                  theme={theme}
                >
                  {section.title}
                </InternalNavLink>
              )))}
          </Nav>
          <button
            onClick={handleMicClick}
            className={`mic-btn ${isListening ? 'listening' : ''}`}
            aria-label={isListening ? 'Stop voice recognition' : 'Start voice recognition'}
            type="button"
          >
            🎤

            <span className="tooltip">
              {isListening ? 'Stop Listening' : 'Speak to navigate (e.g. “Home Page”, “Projects Page”)'}
            </span>
          </button>
          <ThemeToggler
            onClick={() => setExpanded(false)}
          />
        </Navbar.Collapse>
      </Container>
    </Navbar >
  );
};

const NavBarWithRouter = withRouter(NavBar);
export default NavBarWithRouter;
